import{_ as t,c as n,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Erweiterte Funktionen","description":"Lerne die Konfiguration der erweiterten Funktionen von Clawdbot kennen, einschließlich KI-Modellkonfiguration, Multi-Agent-Zusammenarbeit, Browserautomatisierung, Befehlsausführungs-Tools, Web-Such-Tools, Canvas-Visualisierungsoberfläche, Sprachsteuerung und TTS, Gedächtnissystem, Cron-zeitgesteuerte Aufgaben, Skill-Plattform, Sicherheits-Sandbox und Remote-Gateway.","frontmatter":{"title":"Erweiterte Funktionen","sidebarTitle":"KI-Superkräfte freischalten","subtitle":"Erweiterte Funktionen","description":"Lerne die Konfiguration der erweiterten Funktionen von Clawdbot kennen, einschließlich KI-Modellkonfiguration, Multi-Agent-Zusammenarbeit, Browserautomatisierung, Befehlsausführungs-Tools, Web-Such-Tools, Canvas-Visualisierungsoberfläche, Sprachsteuerung und TTS, Gedächtnissystem, Cron-zeitgesteuerte Aufgaben, Skill-Plattform, Sicherheits-Sandbox und Remote-Gateway.","prerequisite":["start/getting-started","start/gateway-startup"],"order":185},"headers":[],"relativePath":"de/moltbot/moltbot/advanced/index.md","filePath":"de/moltbot/moltbot/advanced/index.md"}'),r={name:"de/moltbot/moltbot/advanced/index.md"};function s(o,e,l,u,h,d){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="erweiterte-funktionen" tabindex="-1">Erweiterte Funktionen <a class="header-anchor" href="#erweiterte-funktionen" aria-label="Permalink to &quot;Erweiterte Funktionen&quot;">​</a></h1><h2 id="kapitelubersicht" tabindex="-1">Kapitelübersicht <a class="header-anchor" href="#kapitelubersicht" aria-label="Permalink to &quot;Kapitelübersicht&quot;">​</a></h2><p>Dieses Kapitel führt tief in die erweiterten Funktionen von Clawdbot ein und hilft dir, die leistungsstarken Fähigkeiten deines KI-Assistenten voll zu nutzen. Von der KI-Modellkonfiguration und Multi-Agent-Zusammenarbeit bis hin zur Browserautomatisierung, Gedächtnissystem und Sprachfunktionen – du kannst je nach Bedarf auswählen, was du lernen möchtest.</p><div class="info custom-block"><p class="custom-block-title">Voraussetzungen</p><p>Bevor du dieses Kapitel bearbeitest, schließe bitte folgende Inhalte ab:</p><ul><li><a href="./../../start/getting-started/">Schnellstart</a></li><li><a href="./../../start/gateway-startup/">Gateway starten</a></li></ul></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Je nach Bedarf kannst du verschiedene Lernpfade wählen:</p><h3 id="🚀-schnellstart-pfad-empfohlen-fur-anfanger" tabindex="-1">🚀 Schnellstart-Pfad (empfohlen für Anfänger) <a class="header-anchor" href="#🚀-schnellstart-pfad-empfohlen-fur-anfanger" aria-label="Permalink to &quot;🚀 Schnellstart-Pfad (empfohlen für Anfänger)&quot;">​</a></h3><ol><li><a href="./models-auth/">KI-Modell- und Authentifizierungskonfiguration</a> – Konfiguriere dein bevorzugtes KI-Modell</li><li><a href="./tools-exec/">Befehlsausführungs-Tools und Genehmigung</a> – Lass die KI sicher Befehle ausführen</li><li><a href="./tools-web/">Web-Suche und Extraktions-Tools</a> – Erweitere die Wissenserfassung der KI</li></ol><h3 id="🤖-ki-fahigkeitserweiterungspfad" tabindex="-1">🤖 KI-Fähigkeitserweiterungspfad <a class="header-anchor" href="#🤖-ki-fahigkeitserweiterungspfad" aria-label="Permalink to &quot;🤖 KI-Fähigkeitserweiterungspfad&quot;">​</a></h3><ol><li><a href="./session-management/">Sitzungsverwaltung und Multi-Agent</a> – Verstehe den KI-Zusammenarbeitsmechanismus</li><li><a href="./memory-system/">Gedächtnissystem und Vektorsuche</a> – Lass die KI wichtige Informationen speichern</li><li><a href="./skills-platform/">Skill-Plattform und ClawdHub</a> – Nutze und teile Skill-Pakete</li></ol><h3 id="🔧-automatisierungs-tool-pfad" tabindex="-1">🔧 Automatisierungs-Tool-Pfad <a class="header-anchor" href="#🔧-automatisierungs-tool-pfad" aria-label="Permalink to &quot;🔧 Automatisierungs-Tool-Pfad&quot;">​</a></h3><ol><li><a href="./tools-browser/">Browserautomatisierungs-Tools</a> – Webseitenoperationen automatisieren</li><li><a href="./cron-automation/">Cron-zeitgesteuerte Aufgaben und Webhook</a> – Zeitgesteuerte Aufgaben und Ereignisauslösung</li><li><a href="./remote-gateway/">Remote-Gateway und Tailscale</a> – Fernzugriff auf deinen KI-Assistenten</li></ol><h3 id="🎨-interaktionserfahrungspfad" tabindex="-1">🎨 Interaktionserfahrungspfad <a class="header-anchor" href="#🎨-interaktionserfahrungspfad" aria-label="Permalink to &quot;🎨 Interaktionserfahrungspfad&quot;">​</a></h3><ol><li><a href="./canvas/">Canvas-Visualisierungsoberfläche und A2UI</a> – Visuelle Interaktionsoberfläche</li><li><a href="./voice-tts/">Sprachsteuerung und Text-zu-Sprache</a> – Sprachinteraktionsfunktionen</li></ol><h3 id="🔒-sicherheit-und-bereitstellungspfad" tabindex="-1">🔒 Sicherheit und Bereitstellungspfad <a class="header-anchor" href="#🔒-sicherheit-und-bereitstellungspfad" aria-label="Permalink to &quot;🔒 Sicherheit und Bereitstellungspfad&quot;">​</a></h3><ol><li><a href="./security-sandbox/">Sicherheit und Sandbox-Isolation</a> – Vertiefte Einblicke in Sicherheitsmechanismen</li><li><a href="./remote-gateway/">Remote-Gateway und Tailscale</a> – Sicherer Fernzugriff</li></ol><h2 id="unterseiten-navigation" tabindex="-1">Unterseiten-Navigation <a class="header-anchor" href="#unterseiten-navigation" aria-label="Permalink to &quot;Unterseiten-Navigation&quot;">​</a></h2><h3 id="kernkonfiguration" tabindex="-1">Kernkonfiguration <a class="header-anchor" href="#kernkonfiguration" aria-label="Permalink to &quot;Kernkonfiguration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./models-auth/">KI-Modell- und Authentifizierungskonfiguration</a></td><td>Konfiguration verschiedener KI-Modellanbieter und Authentifizierungsmethoden wie Anthropic, OpenAI, OpenRouter, Ollama</td><td>15 Minuten</td></tr><tr><td><a href="./session-management/">Sitzungsverwaltung und Multi-Agent</a></td><td>Lerne Kernkonzepte wie Sitzungsmodelle, Sitzungsisolierung, Unter-Agent-Zusammenarbeit, Kontextkompression</td><td>20 Minuten</td></tr></tbody></table><h3 id="tool-system" tabindex="-1">Tool-System <a class="header-anchor" href="#tool-system" aria-label="Permalink to &quot;Tool-System&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./tools-browser/">Browserautomatisierungs-Tools</a></td><td>Nutze Browser-Tools für Webseitenautomatisierung, Screenshots, Formularoperationen</td><td>25 Minuten</td></tr><tr><td><a href="./tools-exec/">Befehlsausführungs-Tools und Genehmigung</a></td><td>Konfiguration und Nutzung des exec-Tools, Verständnis des Sicherheitsgenehmigungsmechanismus und Berechtigungssteuerung</td><td>15 Minuten</td></tr><tr><td><a href="./tools-web/">Web-Suche und Extraktions-Tools</a></td><td>Nutze die Tools web_search und web_fetch für Netzwerksuche und Inhaltsextraktion</td><td>20 Minuten</td></tr></tbody></table><h3 id="interaktionserfahrung" tabindex="-1">Interaktionserfahrung <a class="header-anchor" href="#interaktionserfahrung" aria-label="Permalink to &quot;Interaktionserfahrung&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./canvas/">Canvas-Visualisierungsoberfläche und A2UI</a></td><td>Verstehe Canvas A2UI-Push-Mechanismus, visuelle Oberflächenoperationen und benutzerdefinierte Oberflächen</td><td>20 Minuten</td></tr><tr><td><a href="./voice-tts/">Sprachsteuerung und Text-zu-Sprache</a></td><td>Konfiguration von Voice Wake, Talk Mode und TTS-Anbietern, Implementierung der Sprachinteraktion</td><td>15 Minuten</td></tr></tbody></table><h3 id="intelligente-erweiterung" tabindex="-1">Intelligente Erweiterung <a class="header-anchor" href="#intelligente-erweiterung" aria-label="Permalink to &quot;Intelligente Erweiterung&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./memory-system/">Gedächtnissystem und Vektorsuche</a></td><td>Konfiguration und Nutzung des Gedächtnissystems (SQLite-vec, FTS5, hybride Suche)</td><td>25 Minuten</td></tr><tr><td><a href="./skills-platform/">Skill-Plattform und ClawdHub</a></td><td>Verständnis des Skill-Systems, Bundled/Managed/Workspace-Skills, ClawdHub-Integration</td><td>20 Minuten</td></tr></tbody></table><h3 id="automatisierung-und-bereitstellung" tabindex="-1">Automatisierung und Bereitstellung <a class="header-anchor" href="#automatisierung-und-bereitstellung" aria-label="Permalink to &quot;Automatisierung und Bereitstellung&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Cron-zeitgesteuerte Aufgaben und Webhook</a></td><td>Konfiguration zeitgesteuerter Aufgaben, Webhook-Auslösung, Gmail Pub/Sub und weitere Automatisierungsfunktionen</td><td>20 Minuten</td></tr><tr><td><a href="./remote-gateway/">Remote-Gateway und Tailscale</a></td><td>Fernzugriff auf das Gateway über Tailscale Serve/Funnel oder SSH-Tunnel</td><td>15 Minuten</td></tr></tbody></table><h3 id="sicherheitsmechanismen" tabindex="-1">Sicherheitsmechanismen <a class="header-anchor" href="#sicherheitsmechanismen" aria-label="Permalink to &quot;Sicherheitsmechanismen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thema</th><th>Beschreibung</th><th>Geschätzte Zeit</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">Sicherheit und Sandbox-Isolation</a></td><td>Verständnis des Sicherheitsmodells, Tool-Berechtigungssteuerung, Sandbox-Isolation, Containerisierungsbereitstellung</td><td>20 Minuten</td></tr></tbody></table><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels kannst du:</p><ol><li><strong>Vertiefte Einsicht</strong> – Siehe <a href="./../../faq/troubleshooting/">Fehlerbehebung</a> um aufgetretene Probleme zu lösen</li><li><strong>Bereitstellung verstehen</strong> – Siehe <a href="./../../appendix/deployment/">Bereitstellungsoptionen</a> um Clawdbot in einer Produktionsumgebung bereitzustellen</li><li><strong>Erweiterungen entwickeln</strong> – Siehe <a href="./../../appendix/development/">Entwicklerhandbuch</a> um zu lernen, wie man Plugins entwickelt und Code beiträgt</li><li><strong>Konfiguration ansehen</strong> – Siehe <a href="./../../appendix/config-reference/">Vollständige Konfigurationsreferenz</a> um alle Konfigurationsoptionen zu verstehen</li></ol><div class="tip custom-block"><p class="custom-block-title">Lernempfehlung</p><p>Wir empfehlen, den Lernpfad entsprechend deinen tatsächlichen Anforderungen zu wählen. Wenn du unsicher bist, wo du beginnen sollst, kannst du dem „Schnellstart-Pfad&quot; schrittweise folgen. Andere Themen können bei Bedarf vertieft werden.</p></div>',33)])])}const g=t(r,[["render",s]]);export{f as __pageData,g as default};
